namespace sv_114427141b8f4478ad757a5f6e2052ec.Client.Models;

public class Shipment
{
    public string TrackingNumber { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTimeOffset? EstimatedDelivery { get; set; }
    public List<StatusUpdate> Updates { get; set; } = [];
}

public class StatusUpdate
{
    public string Description { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTimeOffset Timestamp { get; set; }
}

using sv_114427141b8f4478ad757a5f6e2052ec.Client.Models;

namespace sv_114427141b8f4478ad757a5f6e2052ec.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_114427141b8f4478ad757a5f6e2052ec.Client.Models;

namespace sv_114427141b8f4478ad757a5f6e2052ec.Client.Services;

public class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var shipment = await httpClient.GetFromJsonAsync<Shipment>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return shipment ?? throw new InvalidOperationException("Shipment not found.");
    }
}

using sv_114427141b8f4478ad757a5f6e2052ec.Client.Models;
using sv_114427141b8f4478ad757a5f6e2052ec.Client.Services;

namespace sv_114427141b8f4478ad757a5f6e2052ec.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 26, 17, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate
                {
                    Description = "Package picked up",
                    Location = "New York, NY",
                    Timestamp = new DateTimeOffset(2026, 5, 20, 9, 30, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Departed facility",
                    Location = "New York, NY",
                    Timestamp = new DateTimeOffset(2026, 5, 20, 14, 0, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Arrived at sorting center",
                    Location = "Chicago, IL",
                    Timestamp = new DateTimeOffset(2026, 5, 22, 8, 15, 0, TimeSpan.Zero)
                }
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate
                {
                    Description = "Package picked up",
                    Location = "Seattle, WA",
                    Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "In transit",
                    Location = "Portland, OR",
                    Timestamp = new DateTimeOffset(2026, 5, 19, 6, 45, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Out for delivery",
                    Location = "San Francisco, CA",
                    Timestamp = new DateTimeOffset(2026, 5, 21, 8, 0, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Delivered",
                    Location = "San Francisco, CA",
                    Timestamp = new DateTimeOffset(2026, 5, 21, 11, 32, 0, TimeSpan.Zero)
                }
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate
                {
                    Description = "Label created",
                    Location = "Dallas, TX",
                    Timestamp = new DateTimeOffset(2026, 5, 23, 7, 0, 0, TimeSpan.Zero)
                }
            ]
        }
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

